// Generated by UntilizeCodegen — TRISC compute: pack_untilize per tile-row block.
// Input: cb_in has tiles in row-major tile order (Wt tiles per tile-row).
// Output: cb_out has RM sticks (Wt pages per tile-row, each page = one untilized tile).
//
// For each tile-row: wait for Wt tiles, pack_untilize_block to produce RM output,
// push Wt pages to cb_out, pop Wt tiles from cb_in.
//
// CT args: [per_core_block_cnt, Wt, cb_in, cb_out, max_bct]
// max_bct is passed explicitly (4 for FP32/INT32, 8 for BF16/BF8) to avoid
// reliance on DST_ACCUM_MODE preprocessor define which may not be set by
// ComputeConfigDescriptor.fp32_dest_acc_en.
#include <cstdint>

#include "api/compute/eltwise_unary/eltwise_unary.h"
#include "api/compute/untilize.h"
#include "api/compute/pack_untilize.h"

// Helper: compute optimal num_blocks_per_col for pack_untilize blocking
constexpr uint32_t compute_num_blocks_per_column(uint32_t per_core_block_tile_cnt, uint32_t max_bct) {
    for (uint32_t bct = max_bct; bct >= 1; --bct) {
        if (per_core_block_tile_cnt % bct == 0) {
            return per_core_block_tile_cnt / bct;
        }
    }
    return 1;
}

void kernel_main() {
    constexpr uint32_t per_core_block_cnt = get_compile_time_arg_val(0);       // num tile-rows this core handles
    constexpr uint32_t per_core_block_tile_cnt = get_compile_time_arg_val(1);  // Wt = tiles per tile-row
    constexpr uint32_t src_cb_id = get_compile_time_arg_val(2);
    constexpr uint32_t out_cb_id = get_compile_time_arg_val(3);
    constexpr uint32_t max_bct = get_compile_time_arg_val(4);  // 4 for FP32, 8 for BF16

    // Compute optimal blocking for pack_untilize
    constexpr uint32_t num_blocks_per_col = compute_num_blocks_per_column(per_core_block_tile_cnt, max_bct);
    constexpr uint32_t block_ct_dim = per_core_block_tile_cnt / num_blocks_per_col;
    constexpr uint32_t full_ct_dim = per_core_block_tile_cnt;

    unary_op_init_common(src_cb_id, out_cb_id);
    pack_untilize_init<block_ct_dim, full_ct_dim>(src_cb_id, out_cb_id);

    for (uint32_t r = 0; r < per_core_block_cnt; ++r) {
        cb_reserve_back(out_cb_id, full_ct_dim);
        for (uint32_t b = 0; b < num_blocks_per_col; ++b) {
            cb_wait_front(src_cb_id, block_ct_dim);
            pack_untilize_block<block_ct_dim, full_ct_dim>(src_cb_id, 1, out_cb_id, b);
            cb_pop_front(src_cb_id, block_ct_dim);
        }
        cb_push_back(out_cb_id, full_ct_dim);
    }
    pack_untilize_uninit(out_cb_id);
}
